package main

import (
	"github.com/dustin/go-broadcast"
)

type Message struct {
	UserId string
	RoomId string
	Text   string
}

type Listener struct {
	RoomId string
	Chan   chan interface{}
}

type Manager struct {
	roomChannels map[string]broadcast.Broadcaster
	open         chan *Listener
	close        chan *Listener
	delete       chan string
	messages     chan *Message
}

func NewRoomManager() *Manager {
	manager := &Manager{
		roomChannels: make(map[string]broadcast.Broadcaster),
		open:         make(chan *Listener, 100),
		close:        make(chan *Listener, 100),
		delete:       make(chan string, 100),
		messages:     make(chan *Message, 100),
	}

	go manager.run()
	return manager
}

func (m *Manager) run() {
	for {
		select {
		case listener := <-m.open:
			m.register(listener)
		case listener := <-m.close:
			m.deregister(listener)
		case roomid := <-m.delete:
			m.deleteBroadcast(roomid)
		case message := <-m.messages:
			m.room(message.RoomId).Submit(message.UserId + ": " + message.Text)
		}
	}
}

func (m *Manager) register(listener *Listener) {
	m.room(listener.RoomId).Register(listener.Chan)
}

func (m *Manager) deregister(listener *Listener) {
	m.room(listener.RoomId).Unregister(listener.Chan)
	close(listener.Chan)
}

func (m *Manager) deleteBroadcast(roomid string) {
	b, ok := m.roomChannels[roomid]
	if ok {
		b.Close()
		delete(m.roomChannels, roomid)
	}
}

func (m *Manager) room(roomid string) broadcast.Broadcaster {
	b, ok := m.roomChannels[roomid]
	if !ok {
		b = broadcast.NewBroadcaster(10)
		m.roomChannels[roomid] = b
	}
	return b
}

func (m *Manager) OpenListener(roomid string) chan interface{} {
	listener := make(chan interface{})
	m.open <- &Listener{
		RoomId: roomid,
		Chan:   listener,
	}
	return listener
}

func (m *Manager) CloseListener(roomid string, channel chan interface{}) {
	m.close <- &Listener{
		RoomId: roomid,
		Chan:   channel,
	}
}

func (m *Manager) DeleteBroadcast(roomid string) {
	m.delete <- roomid
}

func (m *Manager) Submit(userid, roomid, text string) {
	msg := &Message{
		UserId: userid,
		RoomId: roomid,
		Text:   text,
	}
	m.messages <- msg
}

package field

import (
	"gorm.io/gorm/clause"
)

// newGenerics create new generic field type
func newGenerics[T any](e expr) genericsField[T] {
	return genericsField[T]{e}
}

// genericsField a generics field struct
// serving as a base field type, offers a suite of fundamental methods/functions for database operations."
type genericsField[T any] struct{ expr }

// Eq judge equal
func (field genericsField[T]) Eq(value T) Expr {
	return expr{e: clause.Eq{Column: field.RawExpr(), Value: value}}
}

// Neq judge not equal
func (field genericsField[T]) Neq(value T) Expr {
	return expr{e: clause.Neq{Column: field.RawExpr(), Value: value}}
}

// In ...
func (field genericsField[T]) In(values ...T) Expr {
	return expr{e: clause.IN{Column: field.RawExpr(), Values: field.toSlice(values...)}}
}

// NotIn ...
func (field genericsField[T]) NotIn(values ...T) Expr {
	return expr{e: clause.Not(field.In(values...).expression())}
}

// Gt ...
func (field genericsField[T]) Gt(value T) Expr {
	return expr{e: clause.Gt{Column: field.RawExpr(), Value: value}}
}

// Gte ...
func (field genericsField[T]) Gte(value T) Expr {
	return expr{e: clause.Gte{Column: field.RawExpr(), Value: value}}
}

// Lt ...
func (field genericsField[T]) Lt(value T) Expr {
	return expr{e: clause.Lt{Column: field.RawExpr(), Value: value}}
}

// Lte ...
func (field genericsField[T]) Lte(value T) Expr {
	return expr{e: clause.Lte{Column: field.RawExpr(), Value: value}}
}

// Like ...
func (field genericsField[T]) Like(value string) Expr {
	return expr{e: clause.Like{Column: field.RawExpr(), Value: value}}
}

// NotLike ...
func (field genericsField[T]) NotLike(value string) Expr {
	return expr{e: clause.Not(field.Like(value).expression())}
}

// Value ...
func (field genericsField[T]) Value(value T) AssignExpr {
	return field.value(value)
}

// Sum ...
func (field genericsField[T]) Sum() genericsField[T] {
	return genericsField[T]{field.sum()}
}

// IfNull ...
func (field genericsField[T]) IfNull(value T) Expr {
	return field.ifNull(value)
}

// Field ...
func (field genericsField[T]) Field(value []interface{}) Expr {
	return field.field(value)
}

func (field genericsField[T]) toSlice(values ...T) []interface{} {
	slice := make([]interface{}, len(values))
	for i, v := range values {
		slice[i] = v
	}
	return slice
}

package types

import (
	"github.com/swaggo/swag/testdata/enums/consts"
)

type Class int

const (
	None Class = -1
	A    Class = consts.Base + (iota+1-1)*2/2%100 - (1&1 | 1) + (2 ^ 2) // AAA
	B                                                                   /* BBB */
	C
	D = C + 1
	F = Class(5)
	//G is not enum
	G = H + 10
	//H is not enum
	H = 10
	//I is not enum
	I = int(F + 2)
)

const J = 1 << uint16(I)

type Mask int

const (
	Mask1 Mask = 0x02 << iota >> 1 // Mask1
	Mask2                          /* Mask2 */
	Mask3                          // Mask3
	Mask4                          // Mask4
	Mask5 = Mask(A + B)
)

type Type string

const (
	// Teacher this line is ignored by enum comment
	// teacher
	Teacher      Type = "teacher"
	Student      Type = "student" /* student */
	Other        Type = "Other"   // Other
	Unknown           = "Unknown"
	OtherUnknown      = string(Other + Unknown)
)

type Sex rune

const (
	Male   Sex = 'M'
	Female Sex = 'F'
)

type Difficulty string

const (
	DifficultyEasy   Difficulty = "easy"   // @name Easy
	DifficultyMedium Difficulty = "medium" // @Name Medium This one also has a comment
	DifficultyHard   Difficulty = "hard"   // This means really hard
)

type SecurityClearance int

const (
	SecurityClearancePublic    SecurityClearance = iota // @name Public
	SecurityClearanceSensitive                          // Name override and comment rules apply here just as above
	SecurityClearanceSecret                             // @name SuperSecret This one has a name override and a comment
)

type (
	GenericDifficulty[T any] string
	Level                    int
)

const (
	GenericDifficultyEasy   GenericDifficulty[Level] = "g_easy"   // @name GenericEasy
	GenericDifficultyMedium GenericDifficulty[Level] = "g_medium" // @name GenericMedium This one also has a comment
	GenericDifficultyHard   GenericDifficulty[Level] = "g_hard"   // This means really hard
)

type Person struct {
	Name              string
	Class             Class
	Mask              Mask
	Type              Type
	Sex               Sex
	Difficulty        Difficulty
	GenericDifficulty GenericDifficulty[Level]
	SecurityClearance SecurityClearance
}

type PersonWithArrayEnum struct {
	Name              string
	Class             []Class
	Mask              []Mask
	Difficulty        []Difficulty
	GenericDifficulty []GenericDifficulty[Level]
	SecurityClearance []SecurityClearance
	Type              Type
}

package swag

import (
	"go/token"
	"os"
	"path/filepath"
	"slices"

	"golang.org/x/tools/go/packages"
)

func (parser *Parser) loadPackagesAndDeps(searchDirs []string, absMainAPIFilePath string) error {
	mode := packages.NeedName | packages.NeedFiles | packages.NeedCompiledGoFiles | packages.NeedImports |
		packages.NeedTypes | packages.NeedTypesSizes | packages.NeedSyntax | packages.NeedTypesInfo
	if parser.ParseDependency > 0 {
		mode |= packages.NeedDeps
	}

	absDirs := make([]string, 0, len(searchDirs)+1)
	absDirs = append(absDirs, filepath.Dir(absMainAPIFilePath))
	for _, dir := range searchDirs {
		absDir, err := filepath.Abs(dir)
		if err != nil {
			return err
		}
		// load all subpackages keep the same logic with Parser.getAllGoFileInfo
		absDirs = append(absDirs, absDir+"/...")
	}

	fset := token.NewFileSet()
	pkgs, err := packages.Load(&packages.Config{
		Mode: mode,
		Fset: fset,
	}, absDirs...)
	if err != nil {
		return err
	}
	for _, pkg := range pkgs {
		for _, e := range pkg.Errors {
			return e
		}
	}

	err = parser.walkPackages(pkgs, func(pkg *packages.Package) error {
		parseFlag := ParseFlag(ParseAll)
		if !slices.Contains(pkgs, pkg) {
			parseFlag = parser.ParseDependency
		}
		for i, file := range pkg.CompiledGoFiles {
			// TODO handle vendor?
			fileInfo, err := os.Stat(file)
			if err != nil {
				return err
			}
			if parser.Skip(file, fileInfo) != nil {
				continue
			}
			if err = parser.packages.CollectAstFile(fset, pkg.PkgPath, file, pkg.Syntax[i], parseFlag); err != nil {
				return err
			}
		}
		return nil
	})

	parser.packages.AddPackages(pkgs)
	return err
}

func (parser *Parser) walkPackages(pkgs []*packages.Package, f func(p *packages.Package) error) error {
	pkgSeen := make(map[string]struct{})
	return parser.walkPackagesInternal(pkgs, f, pkgSeen)
}

func (parser *Parser) walkPackagesInternal(pkgs []*packages.Package, f func(p *packages.Package) error,
	pkgSeen map[string]struct{}) error {
	for _, pkg := range pkgs {
		if parser.skipPackageByPrefix(pkg.PkgPath) {
			continue
		}
		if _, ok := pkgSeen[pkg.PkgPath]; ok {
			continue
		}
		pkgSeen[pkg.PkgPath] = struct{}{}

		if err := f(pkg); err != nil {
			return err
		}

		if parser.ParseDependency > 0 {
			imports := make([]*packages.Package, 0, len(pkg.Imports))
			for _, dep := range pkg.Imports {
				imports = append(imports, dep)
			}
			if err := parser.walkPackagesInternal(imports, f, pkgSeen); err != nil {
				return err
			}
		}
	}
	return nil
}

package swag

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"go/build"
	"os/exec"
	"path/filepath"
	"slices"
)

func listPackages(ctx context.Context, dirs []string, env []string, args ...string) ([]*build.Package, error) {
	pkgMap := make(map[string]*build.Package)
	for i, dir := range dirs {
		pkgs, err := listOnePackages(ctx, dir, env, args...)
		if err != nil {
			if i == 0 {
				return nil, fmt.Errorf("pkg %s cannot find all dependencies, %s", dir, err)
			}
			continue // ignore search dir load error?
		}
		for _, pkg := range pkgs {
			pkgMap[pkg.Dir] = pkg
		}
	}
	pkgs := make([]*build.Package, 0, len(pkgMap))
	for _, pkg := range pkgMap {
		pkgs = append(pkgs, pkg)
	}
	slices.SortFunc(pkgs, func(a, b *build.Package) int {
		if a.Dir < b.Dir {
			return -1
		} else if a.Dir > b.Dir {
			return 1
		}
		return 0
	})
	return pkgs, nil
}

func listOnePackages(ctx context.Context, dir string, env []string, args ...string) (pkgs []*build.Package, finalErr error) {
	cmd := exec.CommandContext(ctx, "go", append([]string{"list", "-json", "-e"}, args...)...)
	cmd.Env = env
	cmd.Dir = dir

	stdout, err := cmd.StdoutPipe()
	if err != nil {
		return nil, err
	}
	var stderrBuf bytes.Buffer
	cmd.Stderr = &stderrBuf
	defer func() {
		if (finalErr != nil) && (stderrBuf.Len() > 0) {
			finalErr = fmt.Errorf("%v\n%s", finalErr, stderrBuf.Bytes())
		}
	}()

	err = cmd.Start()
	if err != nil {
		return nil, err
	}
	dec := json.NewDecoder(stdout)
	for dec.More() {
		var pkg build.Package
		err = dec.Decode(&pkg)
		if err != nil {
			return nil, err
		}
		pkgs = append(pkgs, &pkg)
	}
	err = cmd.Wait()
	if err != nil {
		return nil, err
	}
	return pkgs, nil
}

func (parser *Parser) getAllGoFileInfoFromDepsByList(pkg *build.Package, parseFlag ParseFlag) error {
	ignoreInternal := pkg.Goroot && !parser.ParseInternal
	if ignoreInternal { // ignored internal
		return nil
	}

	if parser.skipPackageByPrefix(pkg.ImportPath) {
		return nil // ignored by user-defined package path prefixes
	}

	srcDir := pkg.Dir
	var err error
	for i := range pkg.GoFiles {
		err = parser.parseFile(pkg.ImportPath, filepath.Join(srcDir, pkg.GoFiles[i]), nil, parseFlag)
		if err != nil {
			return err
		}
	}

	// parse .go source files that import "C"
	for i := range pkg.CgoFiles {
		err = parser.parseFile(pkg.ImportPath, filepath.Join(srcDir, pkg.CgoFiles[i]), nil, parseFlag)
		if err != nil {
			return err
		}
	}

	return nil
}

