	"github.com/xinliangnote/go-gin-api/internal/websocket/sysmessage"
	"github.com/xinliangnote/go-gin-api/pkg/timeutil"
)

type sendMessageRequest struct {
	Message string `form:"message"` // 消息内容
}

type sendMessageResponse struct {
	Status string `json:"status"` // 状态
}

// SendMessage 发送消息
// @Summary 发送消息
// @Description 发送消息
// @Tags API.tool
// @Accept application/x-www-form-urlencoded
// @Produce json
// @Param message formData string true "消息内容"
// @Success 200 {object} sendMessageResponse
// @Failure 400 {object} code.Failure
// @Router /api/tool/send_message [post]
// @Security LoginToken
func (h *handler) SendMessage() core.HandlerFunc {
	type messageBody struct {
		Username string `json:"username"`
		Message  string `json:"message"`
		Time     string `json:"time"`
	}

	return func(ctx core.Context) {
		req := new(sendMessageRequest)
		res := new(sendMessageResponse)
		if err := ctx.ShouldBindForm(req); err != nil {
			ctx.AbortWithError(core.Error(
				http.StatusBadRequest,
				code.ParamBindError,
				validation.Error(err)).WithError(err),
			)
			return
		}

		conn, err := sysmessage.GetConn()
		if err != nil {
			ctx.AbortWithError(core.Error(
				http.StatusBadRequest,
				code.SocketConnectError,
				code.Text(code.SocketConnectError)).WithError(err),
			)
			return
		}

		messageData := new(messageBody)
		messageData.Username = ctx.SessionUserInfo().UserName
		messageData.Message = req.Message
		messageData.Time = timeutil.CSTLayoutString()

		messageJsonData, err := json.Marshal(messageData)
		if err != nil {
			ctx.AbortWithError(core.Error(
				http.StatusBadRequest,
				code.SocketSendError,
				code.Text(code.SocketSendError)).WithError(err),
			)
			return
		}

		err = conn.OnSend(messageJsonData)
		if err != nil {
			ctx.AbortWithError(core.Error(
				http.StatusBadRequest,
				code.SocketSendError,
				code.Text(code.SocketSendError)).WithError(err),
			)
			return
		}

		res.Status = "OK"
		ctx.Payload(res)
	}
}

package internal

import (
	"github.com/zeromicro/go-zero/core/logx"
	"google.golang.org/grpc/grpclog"
)

// because grpclog.errorLog is not exported, we need to define our own.
const errorLevel = 2

// A Logger is a rpc logger.
type Logger struct{}

func init() {
	grpclog.SetLoggerV2(new(Logger))
}

// Error logs the given args into error log.
func (l *Logger) Error(args ...any) {
	logx.Error(args...)
}

// Errorf logs the given args with format into error log.
func (l *Logger) Errorf(format string, args ...any) {
	logx.Errorf(format, args...)
}

// Errorln logs the given args into error log with newline.
func (l *Logger) Errorln(args ...any) {
	logx.Error(args...)
}

// Fatal logs the given args into error log.
func (l *Logger) Fatal(args ...any) {
	logx.Error(args...)
}

// Fatalf logs the given args with format into error log.
func (l *Logger) Fatalf(format string, args ...any) {
	logx.Errorf(format, args...)
}

// Fatalln logs args into error log with newline.
func (l *Logger) Fatalln(args ...any) {
	logx.Error(args...)
}

// Info ignores the grpc info logs.
func (l *Logger) Info(_ ...any) {
	// ignore builtin grpc info
}

// Infoln ignores the grpc info logs.
