	"github.com/zeromicro/go-zero/internal/devserver"
	"github.com/zeromicro/go-zero/internal/profiling"
)

const (
	// DevMode means development mode.
	DevMode = "dev"
	// TestMode means test mode.
	TestMode = "test"
	// RtMode means regression test mode.
	RtMode = "rt"
	// PreMode means pre-release mode.
	PreMode = "pre"
	// ProMode means production mode.
	ProMode = "pro"
)

type (
	// DevServerConfig is type alias for devserver.Config
	DevServerConfig = devserver.Config

	// A ServiceConf is a service config.
	ServiceConf struct {
		Name       string
		Log        logx.LogConf
		Mode       string `json:",default=pro,options=dev|test|rt|pre|pro"`
		MetricsUrl string `json:",optional"`
		// Deprecated: please use DevServer
		Prometheus prometheus.Config `json:",optional"`
		Telemetry  trace.Config      `json:",optional"`
		DevServer  DevServerConfig   `json:",optional"`
		Shutdown   proc.ShutdownConf `json:",optional"`
		// Profiling is the configuration for continuous profiling.
		Profiling profiling.Config `json:",optional"`
	}
)

// MustSetUp sets up the service, exits on error.
func (sc ServiceConf) MustSetUp() {
	logx.Must(sc.SetUp())
}

// SetUp sets up the service.
func (sc ServiceConf) SetUp() error {
	if len(sc.Log.ServiceName) == 0 {
		sc.Log.ServiceName = sc.Name
	}
	if err := logx.SetUp(sc.Log); err != nil {
		return err
	}

	sc.initMode()
	prometheus.StartAgent(sc.Prometheus)

	if len(sc.Telemetry.Name) == 0 {
		sc.Telemetry.Name = sc.Name
	}
	trace.StartAgent(sc.Telemetry)
	proc.Setup(sc.Shutdown)
	proc.AddShutdownListener(func() {
		trace.StopAgent()
	})

	if len(sc.MetricsUrl) > 0 {
		stat.SetReportWriter(stat.NewRemoteWriter(sc.MetricsUrl))
	}

	devserver.StartAgent(sc.DevServer)
	profiling.Start(sc.Profiling)

	return nil
}

func (sc ServiceConf) initMode() {
	switch sc.Mode {
	case DevMode, TestMode, RtMode, PreMode:
		load.Disable()
		stat.SetReporter(nil)
	}
}

package prof

import (
	"fmt"
	"strings"
	"sync"
	"sync/atomic"
	"time"

	"github.com/zeromicro/go-zero/core/logx"
	"github.com/zeromicro/go-zero/core/threading"
)

type (
	profileSlot struct {
		lifecount int64
		lastcount int64
		lifecycle int64
		lastcycle int64
	}

	profileCenter struct {
		lock  sync.RWMutex
		slots map[string]*profileSlot
	}
)

const flushInterval = 5 * time.Minute

var pc = &profileCenter{
	slots: make(map[string]*profileSlot),
}

func init() {
	flushRepeatedly()
}

func flushRepeatedly() {
	threading.GoSafe(func() {
		for {
			time.Sleep(flushInterval)
			logx.Stat(generateReport())
		}
	})
}

func report(name string, duration time.Duration) {
	slot := loadOrStoreSlot(name, duration)

	atomic.AddInt64(&slot.lifecount, 1)
	atomic.AddInt64(&slot.lastcount, 1)
	atomic.AddInt64(&slot.lifecycle, int64(duration))
	atomic.AddInt64(&slot.lastcycle, int64(duration))
}

func loadOrStoreSlot(name string, duration time.Duration) *profileSlot {
	pc.lock.RLock()
	slot, ok := pc.slots[name]
	pc.lock.RUnlock()

	if ok {
		return slot
	}

	pc.lock.Lock()
	defer pc.lock.Unlock()

	// double-check
	if slot, ok = pc.slots[name]; ok {
		return slot
	}

	slot = &profileSlot{}
	pc.slots[name] = slot
	return slot
}

func generateReport() string {
	var builder strings.Builder
	builder.WriteString("Profiling report\n")
	builder.WriteString("QUEUE,LIFECOUNT,LIFECYCLE,LASTCOUNT,LASTCYCLE\n")

	calcFn := func(total, count int64) string {
		if count == 0 {
			return "-"
		}
		return (time.Duration(total) / time.Duration(count)).String()
	}

	pc.lock.Lock()
	for key, slot := range pc.slots {
		builder.WriteString(fmt.Sprintf("%s,%d,%s,%d,%s\n",
			key,
			slot.lifecount,
			calcFn(slot.lifecycle, slot.lifecount),
			slot.lastcount,
			calcFn(slot.lastcycle, slot.lastcount),
		))

		// reset last cycle stats
		atomic.StoreInt64(&slot.lastcount, 0)
		atomic.StoreInt64(&slot.lastcycle, 0)
	}
	pc.lock.Unlock()

	return builder.String()
}

package internal

import (
	"io"
	"net/http"

	"github.com/golang/protobuf/jsonpb"
	"github.com/golang/protobuf/proto"
	"github.com/jhump/protoreflect/desc"
	"github.com/zeromicro/go-zero/core/logx"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
)

const (
	// MetadataHeaderPrefix is the http prefix that represents custom metadata
	// parameters to or from a gRPC call.
	MetadataHeaderPrefix = "Grpc-Metadata-"

	// MetadataTrailerPrefix is prepended to gRPC metadata as it is converted to
	// HTTP headers in a response handled by go-zero gateway
	MetadataTrailerPrefix = "Grpc-Trailer-"
)

type EventHandler struct {
	Status    *status.Status
	writer    io.Writer
	marshaler jsonpb.Marshaler
}

func NewEventHandler(writer io.Writer, resolver jsonpb.AnyResolver) *EventHandler {
	return &EventHandler{
		writer: writer,
		marshaler: jsonpb.Marshaler{
			EmitDefaults: true,
			AnyResolver:  resolver,
		},
	}
}

func (h *EventHandler) OnReceiveHeaders(md metadata.MD) {
	w, ok := h.writer.(http.ResponseWriter)
	if ok {
		for k, vs := range md {
			header := defaultOutgoingHeaderMatcher(k)
			for _, v := range vs {
				w.Header().Add(header, v)
			}
		}
	}
}

func (h *EventHandler) OnReceiveResponse(message proto.Message) {
	if err := h.marshaler.Marshal(h.writer, message); err != nil {
		logx.Error(err)
	}
}

func (h *EventHandler) OnReceiveTrailers(status *status.Status, md metadata.MD) {
	w, ok := h.writer.(http.ResponseWriter)
	if ok {
		for k, vs := range md {
			header := defaultOutgoingTrailerMatcher(k)
			for _, v := range vs {
				w.Header().Add(header, v)
			}
		}
	}

	h.Status = status
}

func (h *EventHandler) OnResolveMethod(_ *desc.MethodDescriptor) {
}

func (h *EventHandler) OnSendHeaders(_ metadata.MD) {
}

func defaultOutgoingHeaderMatcher(key string) string {
	return MetadataHeaderPrefix + key
}

func defaultOutgoingTrailerMatcher(key string) string {
	return MetadataTrailerPrefix + key
}

